import json
from playwright.sync_api import sync_playwright


class ChituCookies():
    def __init__(self, username, password):
        self.url = 'https://kf.topchitu.com/'
        self.playwright = sync_playwright().start()
        chromium = self.playwright.chromium  # or "firefox" or "webkit".
        self.browser = chromium.launch(headless=True)
        self.username = username
        self.first_cookie = password

    def open(self):
        self.context = self.browser.new_context()
        self.context.add_cookies(json.loads(self.first_cookie)["cookies"])
        self.page = self.context.new_page()
        self.page.goto(self.url)
        # other actions...
        self.page.wait_for_timeout(2 * 1000)
        self.page.locator("xpath=//div[@class='professionLogin']/div").click()
        self.page.wait_for_timeout(2 * 1000)
        self.input_ = self.page.locator(
            # "xpath=//div[@class='openplatform-login-iframe']/h3[text()='检测到您已登录淘宝，可以直接进行授权']/following-sibling::p[1]"
            "xpath=//*[text()='检测到您已登录淘宝，可以直接进行授权']/..//*[text()='授权并登录']"
        )
        self.page.wait_for_timeout(2 * 1000)

    def login_successfully(self):
        if self.input_.count():
            self.page.locator("xpath=//button[@id='sub']").click()
            # 判断登录成功后获取cookies
            self.page.wait_for_timeout(5 * 1000)
            return True
        else:
            return False

    def get_cookies(self):
        cookies = self.context.cookies()
        return cookies

    def close(self):
        # self.page.wait_for_timeout(200000 * 1000)
        self.browser.close()
        self.playwright.stop()

    def main(self):
        """
        破解入口
        :return:
        """
        try:
            self.open()
        except Exception as e:
            self.close()
            print(e)
            return {
                'status': 2,
                'content': '登录失败'
            }
        if self.login_successfully():
            cookies = self.get_cookies()
            self.close()
            return {
                'status': 1,
                'content': cookies
            }
        else:
            self.close()
            return {
                'status': 2,
                'content': '登录失败'
            }


